{
  "files": [
    {
      "path": "README.md",
      "content": "# CSV Parser

This is a simple CSV parser written in TypeScript.
"
    },
    {
      "path": "package.json",
      "content": "{
  "name": "csv-parser",
  "version": "1.0.0",
  "description": "A simple CSV parser",
  "main": "dist/cli.js",
  "scripts": {
    "build": "tsc",
    "test": "node --test tests/oracle.test.js"
  },
  "dependencies": {
    "typescript": "^5.0.0"
  }
}"
    },
    {
      "path": "tsconfig.json",
      "content": "{
  "compilerOptions": {
    "target": "ES6",
    "module": "commonjs",
    "outDir": "dist",
    "strict": true,
    "esModuleInterop": true
  },
  "include": [
    "src/**/*"
  ]
}"
    },
    {
      "path": "src/csv.ts",
      "content": "export class CsvParser {
  parse(content: string): any[] {
    const lines = content.split('\n');
    const headers = lines[0].split(',').map(header => header.trim());
    return lines.slice(1).map(line => {
      const values = line.split(',').map(value => value.trim());
      return headers.reduce((acc, header, index) => ({ ...acc, [header]: values[index] }), {});
    });
  }
}"
    }
  ]
}
